esqlQuery.esql:
TS metrics-ibmmq.otel-*
| STATS qmgr_fs_free_pct = MAX(LAST_OVER_TIME(ibmmq_qmgr_queue_manager_file_system_free_space_percentage))
    BY attributes.qmgr
// Alert when queue manager filesystem free space drops below 20%
// The queue manager filesystem stores configuration and queue data
// Adjust threshold based on your capacity planning requirements
| WHERE qmgr_fs_free_pct IS NOT NULL AND qmgr_fs_free_pct < 20
